    mfa_enforced_at TIMESTAMPTZ,
    risk_score INTEGER NOT NULL DEFAULT 0,
    trust_level mfa_trust_level NOT NULL DEFAULT 'medium',
    adaptive_authentication_triggered BOOLEAN NOT NULL DEFAULT FALSE,
    additional_factors_required INTEGER NOT NULL DEFAULT 0,
    ip_risk_score INTEGER,
    device_risk_score INTEGER,
    location_anomaly BOOLEAN NOT NULL DEFAULT FALSE,
    time_anomaly BOOLEAN NOT NULL DEFAULT FALSE,
    verification_method mfa_verification_method NOT NULL,
    verification_initiated_at TIMESTAMPTZ NOT NULL,
    verification_completed_at TIMESTAMPTZ,
    verification_attempts INTEGER NOT NULL DEFAULT 0,
    max_attempts_allowed INTEGER NOT NULL DEFAULT 5,
    verification_success BOOLEAN,
    verification_time_ms INTEGER,
    device_trust_status device_trust_status NOT NULL DEFAULT 'untrusted',
    is_terminated BOOLEAN NOT NULL DEFAULT FALSE,
    terminated_at TIMESTAMPTZ,
    termination_reason TEXT,
    ip_address TEXT NOT NULL,
    user_agent TEXT,
    device_fingerprint TEXT,
    country TEXT,
    region TEXT,
    city TEXT,
