    longitude DOUBLE PRECISION,
    expires_at TIMESTAMPTZ NOT NULL,
    max_duration_minutes INTEGER NOT NULL DEFAULT 30,
    idle_timeout_minutes INTEGER NOT NULL DEFAULT 15,
    auto_renew_enabled BOOLEAN NOT NULL DEFAULT FALSE,
    last_activity_at TIMESTAMPTZ NOT NULL DEFAULT 'now()',
    extension_count INTEGER NOT NULL DEFAULT 0,
    initiation_time_ms INTEGER NOT NULL,
    total_session_time_ms INTEGER,
    device_performance_score INTEGER,
    network_quality network_quality NOT NULL DEFAULT 'unknown',
    audit_log_required BOOLEAN NOT NULL DEFAULT TRUE,
    data_retention_hours INTEGER NOT NULL DEFAULT 8760,
    status mfa_session_status NOT NULL DEFAULT 'initiated',
    metadata JSONB NOT NULL DEFAULT '{"created_at":null,"updated_at":null,"deleted_at":null,"created_by":null,"updated_by":null,"deleted_by":null}'::jsonb,
